在 get_mastery_trend() 之后新增:

def get_skills_with_recency(self) -> dict[str, dict]:
    """从 skill_masteries JSON blob 读取技能掌握度 + 距上次活动天数.

    Returns:
        {"python_loop": {"mastery": 0.85, "days_elapsed": 12.5}, ...}
    """
    import time, json
    now = time.time()
    profile = self.get_profile()
    masteries = profile.get("skill_masteries", {})
    if not masteries:
        return {}

    last_ts = now
    try:
        row = self.db.execute(
            "SELECT MAX(timestamp) FROM profile_history WHERE session_id = ?",
            (self.session_id,),
        ).fetchone()
        if row and row[0]:
            last_ts = float(row[0])
    except Exception:
        pass

    days_elapsed = max(0.0, (now - last_ts) / 86400.0)
    result = {}
    for skill_name, mastery_val in masteries.items():
        try:
            mv = float(mastery_val)
        except (ValueError, TypeError):
            mv = 0.5
        result[skill_name] = {
            "mastery": round(max(0.0, min(1.0, mv)), 4),
            "days_elapsed": round(days_elapsed, 2),
        }
    return result

